module top_module(IN1, IN2, SEL, OUT);input IN1;
  input IN2;
  input SEL;
  output OUT;

  wire NOT_SEL;
  assign NOT_SEL = ~SEL;

  wire AND1;
  wire temp1_IN1 = IN1;
  wire temp2_NOT_SEL = NOT_SEL;
  assign AND1 = temp1_IN1 & temp2_NOT_SEL;

  wire AND2;
  assign AND2 = IN2 & SEL;

  assign OUT = AND1 | AND2;

endmodule
